headStyles:
body {
  background: var(--dark-bg);
}

.donate-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 2rem;
  margin-bottom: 3rem;
}
.donate-card {
  padding: 2.5rem;
  border-radius: 8px;
  background: rgba(19, 45, 68, 0.5);
  border: 1px solid var(--dark-bg-light);
  transition: all 0.3s;
}
.donate-card.prominent {
  border: 2px solid var(--color-blue);
  position: relative;
}
.donate-card.prominent::before {
  content: "Featured";
  position: absolute;
  top: -12px;
  left: 24px;
  background: var(--color-blue);
  color: var(--text-white);
  font-family: "Montserrat", sans-serif;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  padding: 4px 12px;
  border-radius: 4px;
}
.donate-card h2 {
  font-family: "Montserrat", sans-serif;
  font-size: 1.5rem;
  margin-bottom: 1rem;
  color: var(--text-white);
}
.donate-card p {
  font-family: "Roboto Slab", serif;
  font-size: 1rem;
  margin-bottom: 1.5rem;
  color: var(--text-light);
  line-height: 1.7;
}

.amount-buttons {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-bottom: 1rem;
}
.amount-btn {
  padding: 0.5rem 1rem;
  background-color: var(--dark-bg-lighter);
  color: var(--text-white);
  border: 1px solid var(--dark-bg-light);
  border-radius: 6px;
  text-decoration: none;
  transition: all 0.2s;
  font-family: "Montserrat", sans-serif;
  font-weight: 600;
  font-size: 0.95rem;
}
.amount-btn:hover {
  background-color: var(--color-blue);
  border-color: var(--color-blue);
}

@media (max-width: 768px) {
  .donate-grid {
    grid-template-columns: 1fr;
  }
  .donate-card {
    padding: 1.5rem;
  }
  .amount-buttons {
    flex-direction: column;
  }
  .amount-btn {
    width: 100%;
    text-align: center;
  }
}
